+    #[test]
+    fn clock_advance_multiple_small_steps() {
+        let mut clock = MockClock::new(0);
+        for _ in 0..100 {
+            clock.advance(Duration::from_millis(1));
+        }
+        assert_eq!(clock.now_ms(), 100);
