+
+    #[test]
+    fn clock_schedule_single_timer() {
+        let mut clock = MockClock::new(0);
+        clock.schedule_timer(42);
+        let delta = clock.advance_to_next_timer().unwrap();
+        assert_eq!(delta, Duration::from_millis(42));
